#endif

__device__ __forceinline__ int maximum_dev(int a, int b, int c)
{
    int k;
    if (a <= b) k = b;
    else k = a;

    if (k <= c) return c;
    else return k;
}

__global__ void nw_top_left_kernel(int *input_itemsets, const int *referrence, int max_cols, int penalty, int blk)
{
    int b_index_x = blockIdx.x * blockDim.x + threadIdx.x;
    if (b_index_x >= blk) return;
    int b_index_y = blk - 1 - b_index_x;

    int input_itemsets_l[(BLOCK_SIZE + 1) * (BLOCK_SIZE + 1)];
    int reference_l[BLOCK_SIZE * BLOCK_SIZE];

    for (int i = 0; i < BLOCK_SIZE; ++i) {
        for (int j = 0; j < BLOCK_SIZE; ++j) {
            reference_l[i * BLOCK_SIZE + j] =
                referrence[max_cols * (b_index_y * BLOCK_SIZE + i + 1) + b_index_x * BLOCK_SIZE + j + 1];
        }
    }

    for (int i = 0; i < BLOCK_SIZE + 1; ++i) {
        for (int j = 0; j < BLOCK_SIZE + 1; ++j) {
            input_itemsets_l[i * (BLOCK_SIZE + 1) + j] =
                input_itemsets[max_cols * (b_index_y * BLOCK_SIZE + i) + b_index_x * BLOCK_SIZE + j];
        }
    }

    for (int i = 1; i < BLOCK_SIZE + 1; ++i) {
        for (int j = 1; j < BLOCK_SIZE + 1; ++j) {
            input_itemsets_l[i * (BLOCK_SIZE + 1) + j] = maximum_dev(
                input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + j - 1] + reference_l[(i - 1) * BLOCK_SIZE + j - 1],
                input_itemsets_l[i * (BLOCK_SIZE + 1) + j - 1] - penalty,
                input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + j] - penalty);
        }
    }

    for (int i = 0; i < BLOCK_SIZE; ++i) {
        for (int j = 0; j < BLOCK_SIZE; ++j) {
            input_itemsets[max_cols * (b_index_y * BLOCK_SIZE + i + 1) + b_index_x * BLOCK_SIZE + j + 1] =
                input_itemsets_l[(i + 1) * (BLOCK_SIZE + 1) + j + 1];
        }
    }
}

__global__ void nw_bottom_right_kernel(int *input_itemsets, const int *referrence, int max_cols, int penalty, int blk, int block_width)
{
    int tid = blockIdx.x * blockDim.x + threadIdx.x;
    int b_index_x = (blk - 1) + tid;
    if (b_index_x >= block_width) return;

    int b_index_y = block_width + blk - 2 - b_index_x;

    int input_itemsets_l[(BLOCK_SIZE + 1) * (BLOCK_SIZE + 1)];
    int reference_l[BLOCK_SIZE * BLOCK_SIZE];

    for (int i = 0; i < BLOCK_SIZE; ++i) {
        for (int j = 0; j < BLOCK_SIZE; ++j) {
            reference_l[i * BLOCK_SIZE + j] =
                referrence[max_cols * (b_index_y * BLOCK_SIZE + i + 1) + b_index_x * BLOCK_SIZE + j + 1];
        }
    }

    for (int i = 0; i < BLOCK_SIZE + 1; ++i) {
        for (int j = 0; j < BLOCK_SIZE + 1; ++j) {
            input_itemsets_l[i * (BLOCK_SIZE + 1) + j] =
                input_itemsets[max_cols * (b_index_y * BLOCK_SIZE + i) + b_index_x * BLOCK_SIZE + j];
        }
    }

    for (int i = 1; i < BLOCK_SIZE + 1; ++i) {
        for (int j = 1; j < BLOCK_SIZE + 1; ++j) {
            input_itemsets_l[i * (BLOCK_SIZE + 1) + j] = maximum_dev(
                input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + j - 1] + reference_l[(i - 1) * BLOCK_SIZE + j - 1],
                input_itemsets_l[i * (BLOCK_SIZE + 1) + j - 1] - penalty,
                input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + j] - penalty);
        }
    }

    for (int i = 0; i < BLOCK_SIZE; ++i) {
        for (int j = 0; j < BLOCK_SIZE; ++j) {
            input_itemsets[max_cols * (b_index_y * BLOCK_SIZE + i + 1) + b_index_x * BLOCK_SIZE + j + 1] =
                input_itemsets_l[(i + 1) * (BLOCK_SIZE + 1) + j + 1];
        }
    }
}

void nw_optimized(int *input_itemsets, int *output_itemsets, int *referrence,
                  int max_rows, int max_cols, int penalty)
{
    (void)output_itemsets;
    int *d_input = NULL;
    int *d_ref = NULL;
    size_t transfer_size = (size_t)max_rows * (size_t)max_cols * sizeof(int);

    cudaMalloc((void **)&d_input, transfer_size);
    cudaMalloc((void **)&d_ref, transfer_size);

    cudaMemcpy(d_input, input_itemsets, transfer_size, cudaMemcpyHostToDevice);
    cudaMemcpy(d_ref, referrence, transfer_size, cudaMemcpyHostToDevice);

    int block_width = (max_cols - 1) / BLOCK_SIZE;
    const int threads = 128;

    for (int blk = 1; blk <= block_width; blk++) {
        int count = blk;
        int grid = (count + threads - 1) / threads;
        nw_top_left_kernel<<<grid, threads>>>(d_input, d_ref, max_cols, penalty, blk);
        cudaDeviceSynchronize();
    }

    printf("Processing bottom-right matrix\n");

    for (int blk = 2; blk <= block_width; blk++) {
        int count = block_width - (blk - 1);
        int grid = (count + threads - 1) / threads;
        nw_bottom_right_kernel<<<grid, threads>>>(d_input, d_ref, max_cols, penalty, blk, block_width);
        cudaDeviceSynchronize();
    }

    cudaMemcpy(input_itemsets, d_input, transfer_size, cudaMemcpyDeviceToHost);

    cudaFree(d_input);
    cudaFree(d_ref);
}
